app.use("/", require("./routes"));

const port = process.env.PORT || 5002;

async function startServer() {
  try {
    // Cache the LicenseFeedBacks for tracking utility mapping
    const feedbacks = await db.LicenseFeedBacks.findAll();
    globalThis.sql = globalThis.sql || {};
    globalThis.sql.LicenseFeedBacksCache = feedbacks;
    console.log(`Loaded ${feedbacks.length} LicenseFeedBacks into cache.`);

    // Cache LicensingTime records for estimated date calculations in prod tracking
    const licensingTimes = await db.LicensingTime.findAll();
    globalThis.sql.LicensingTimeCache = licensingTimes.map(r => r.dataValues);
    console.log(`Loaded ${licensingTimes.length} LicensingTimes into cache.`);

    // Pre-build mg_code → LicensingTime record map at startup.
    // For each mg_code we try every associated mg_desc (e.g. SE → "16X40\"", "SEGA", "SPELLS")
    // and keep the first one that fuzzy-matches a LicensingTime record.
    // This avoids repeated fuzzy matching on every request and handles codes with multiple descs.
    const { fuzzyMatchLicensor, fuzzyMatch } = require('./helpers/leadTimeUtils');
    const merchGroups = await db.merchGroup.findAll({ attributes: ['mg_code', 'mg_desc'] });
    const mgCodeDescs = {};
    for (const mg of merchGroups) {
      if (!mg.mg_code) continue;
      if (!mgCodeDescs[mg.mg_code]) mgCodeDescs[mg.mg_code] = [];
      if (mg.mg_desc && !mgCodeDescs[mg.mg_code].includes(mg.mg_desc)) {
        mgCodeDescs[mg.mg_code].push(mg.mg_desc);
      }
    }

    // mg_code (licensor group 05) → LicensingTime record
    const licTimeCache = globalThis.sql.LicensingTimeCache;
    const mgLicTimesMap = {};
    for (const [code, descs] of Object.entries(mgCodeDescs)) {
      for (const desc of descs) {
        const match = fuzzyMatchLicensor(desc, licTimeCache);
        if (match) { mgLicTimesMap[code] = match; break; }
      }
    }
    globalThis.sql.MgLicTimesMap = mgLicTimesMap;
    console.log(`Built LicensingTime map for ${Object.keys(mgLicTimesMap).length} mg_codes.`);

    // mg_code (product type group 01) → FactoryTime record
    // Used to calculate factory days for needed-date backwards calculation.
    const allFactory = await db.FactoryTime.findAll();
    const factoryCache = allFactory.map(r => r.dataValues);
    const mgFactoryTimesMap = {};
    for (const [code, descs] of Object.entries(mgCodeDescs)) {
      for (const desc of descs) {
        const match = fuzzyMatch(desc, factoryCache, 'product_subtype');
        if (match) { mgFactoryTimesMap[code] = match; break; }
      }
    }
    globalThis.sql.MgFactoryTimesMap = mgFactoryTimesMap;
    console.log(`Built FactoryTime map for ${Object.keys(mgFactoryTimesMap).length} mg_codes.`);

    app.listen(port, function () {
      console.log(`🚀 License Tracking Server running on port ${port} in the ${env} environment`);
      console.log(`🌐 Web URL: ${process.env.WEB_URL}`);
      console.log(`🧠 API Address: ${process.env.API_ADDRESS}`);
      console.log(`📦 Schema: ${process.env.SCHEMA}`);
      console.log(`⚙️  Env File: ${envFile}`);
    });
  } catch (error) {
    console.error('Failed to initialize the application:', error);
    process.exit(1);
  }
}

startServer();
